import React, { useState, useEffect } from 'react';
import {
  LineChart, Line, BarChart, Bar, XAxis, YAxis, Tooltip,
  ResponsiveContainer, CartesianGrid, Cell
} from 'recharts';
import api from '../utils/api';
import Sidebar from '../components/common/Sidebar';

const CustomTooltip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null;
  return (
    <div style={{ background: 'var(--bg-card)', border: '1px solid var(--border-light)', borderRadius: 6, padding: '0.6rem 0.85rem', fontSize: '0.8rem' }}>
      <div style={{ color: 'var(--text-muted)', marginBottom: '0.25rem' }}>{label}</div>
      {payload.map((p, i) => (
        <div key={i} style={{ color: p.color || 'var(--accent)' }}>{p.name}: <strong>{p.value}</strong></div>
      ))}
    </div>
  );
};

const GaugeBar = ({ value, max = 100, color, label }) => (
  <div style={{ marginBottom: '1.25rem' }}>
    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.4rem', fontSize: '0.82rem' }}>
      <span style={{ color: 'var(--text-secondary)' }}>{label}</span>
      <span style={{ color, fontWeight: 700, fontFamily: 'var(--font-heading)' }}>{value}%</span>
    </div>
    <div style={{ height: 10, background: 'var(--bg-hover)', borderRadius: 5, overflow: 'hidden' }}>
      <div style={{
        height: '100%', borderRadius: 5,
        background: `linear-gradient(90deg, ${color}88, ${color})`,
        width: `${Math.min(value, 100)}%`,
        transition: 'width 0.6s ease',
      }}/>
    </div>
  </div>
);

export default function PerformanceDashboardPage() {
  const [data, setData] = useState(null);
  const [period, setPeriod] = useState('30');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    setLoading(true);
    api.get(`/dashboard/performance?period=${period}`)
      .then(r => { setData(r.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, [period]);

  const weeklyData = data?.completedByWeek?.map(w => ({
    week: new Date(w.week).toLocaleDateString('fr-FR', { day: '2-digit', month: 'short' }),
    completed: parseInt(w.count),
  })) || [];

  const agingData = data?.backlogAging || [];

  return (
    <div className="page">
      <Sidebar />
      <div className="main-content">
        <div className="page-header">
          <div>
            <h1 style={{ fontSize: '1.3rem', fontFamily: 'var(--font-heading)' }}>Performance Dashboard</h1>
            <p style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginTop: '0.2rem' }}>
              KPIs, lead times, and quality metrics
            </p>
          </div>
          <div style={{ display: 'flex', gap: '0.4rem' }}>
            {[['7','7 days'],['30','30 days'],['90','90 days']].map(([val, label]) => (
              <button key={val} className={`btn btn-sm ${period === val ? 'btn-primary' : 'btn-ghost'}`}
                onClick={() => setPeriod(val)}>{label}</button>
            ))}
          </div>
        </div>

        <div className="page-body">
          {loading ? (
            <div style={{ display: 'flex', justifyContent: 'center', padding: '3rem' }}>
              <span className="spinner" style={{ width: 32, height: 32 }}/>
            </div>
          ) : (
            <>
              {/* KPI row */}
              <div className="grid-4" style={{ marginBottom: '1.5rem' }}>
                <div className="kpi-card">
                  <div className="kpi-value" style={{ color: 'var(--blue)' }}>
                    {data?.avgLeadTimeHours ? `${Math.round(data.avgLeadTimeHours)}h` : '—'}
                  </div>
                  <div className="kpi-label">Avg. Lead Time</div>
                  <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', marginTop: '0.25rem' }}>
                    {data?.avgLeadTimeHours ? `≈ ${(data.avgLeadTimeHours / 24).toFixed(1)} days` : 'No completed requests'}
                  </div>
                </div>
                <div className="kpi-card" style={{ '--accent': data?.onTimeRate >= 80 ? 'var(--green)' : data?.onTimeRate >= 60 ? 'var(--yellow)' : 'var(--red)' }}>
                  <div className="kpi-value" style={{ color: data?.onTimeRate >= 80 ? 'var(--green)' : data?.onTimeRate >= 60 ? 'var(--yellow)' : 'var(--red)' }}>
                    {data?.onTimeRate ?? 0}%
                  </div>
                  <div className="kpi-label">On-Time Delivery</div>
                </div>
                <div className="kpi-card">
                  <div className="kpi-value" style={{ color: data?.reworkRate > 10 ? 'var(--red)' : 'var(--green)' }}>
                    {data?.reworkRate ?? 0}%
                  </div>
                  <div className="kpi-label">Rework Rate</div>
                </div>
                <div className="kpi-card">
                  <div className="kpi-value" style={{ color: data?.failedPrintRate > 5 ? 'var(--red)' : 'var(--green)' }}>
                    {data?.failedPrintRate ?? 0}%
                  </div>
                  <div className="kpi-label">Failed Print Rate</div>
                </div>
              </div>

              {/* Charts */}
              <div className="grid-2" style={{ marginBottom: '1.5rem' }}>
                {/* Completed per week */}
                <div className="card">
                  <h3 style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '1rem' }}>
                    Completed Requests per Week
                  </h3>
                  {weeklyData.length > 0 ? (
                    <ResponsiveContainer width="100%" height={200}>
                      <BarChart data={weeklyData} barSize={24}>
                        <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" vertical={false}/>
                        <XAxis dataKey="week" tick={{ fill: 'var(--text-muted)', fontSize: 11 }} axisLine={false} tickLine={false}/>
                        <YAxis tick={{ fill: 'var(--text-muted)', fontSize: 11 }} axisLine={false} tickLine={false} width={28}/>
                        <Tooltip content={<CustomTooltip/>}/>
                        <Bar dataKey="completed" fill="var(--accent)" radius={[4,4,0,0]} name="Completed"/>
                      </BarChart>
                    </ResponsiveContainer>
                  ) : (
                    <div className="empty-state" style={{ padding: '2rem' }}><p>No completed requests in this period</p></div>
                  )}
                </div>

                {/* Quality metrics */}
                <div className="card">
                  <h3 style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '1.25rem' }}>
                    Quality Metrics
                  </h3>
                  <GaugeBar
                    value={data?.onTimeRate ?? 0}
                    label="On-Time Delivery Rate"
                    color="var(--green)"
                  />
                  <GaugeBar
                    value={100 - (data?.reworkRate ?? 0)}
                    label="First-Pass Success Rate"
                    color="var(--blue)"
                  />
                  <GaugeBar
                    value={100 - (data?.failedPrintRate ?? 0)}
                    label="Print Success Rate"
                    color="var(--cyan)"
                  />
                </div>
              </div>

              {/* Backlog aging */}
              <div className="card">
                <h3 style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '1rem' }}>
                  Backlog Aging
                </h3>
                {agingData.length > 0 ? (
                  <div style={{ display: 'flex', gap: '1rem', flexWrap: 'wrap' }}>
                    {agingData.map((bucket, i) => {
                      const colors = ['var(--green)', 'var(--yellow)', 'var(--accent)', 'var(--red)'];
                      return (
                        <div key={i} style={{
                          flex: '1 1 160px', background: 'var(--bg-hover)',
                          borderRadius: 8, padding: '1rem 1.25rem',
                          border: '1px solid var(--border)',
                          borderTop: `3px solid ${colors[i % colors.length]}`,
                        }}>
                          <div style={{ fontSize: '1.8rem', fontFamily: 'var(--font-heading)', fontWeight: 800, color: colors[i % colors.length] }}>
                            {bucket.count}
                          </div>
                          <div style={{ fontSize: '0.78rem', color: 'var(--text-secondary)', marginTop: '0.2rem' }}>
                            {bucket.age_bucket}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                ) : (
                  <div className="empty-state" style={{ padding: '1.5rem' }}><p>No open requests in backlog</p></div>
                )}
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
